35	    // Note: the internal state data will be cloned by the simulator backend.
36	    std::vector<QuditInfo> v{QuditInfo{Levels, id()}};
37	    getExecutionManager()->initializeState(v, state.internal.get());
38	  }
39	  qudit(const state *s) : qudit(*s) {}
40	  qudit(state *s) : qudit(const_cast<const state *>(s)) {}
41	  qudit(state &s) : qudit(const_cast<const state &>(s)) {}
42	
43	  // Qudits cannot be copied
44	  qudit(const qudit &q) = delete;
45	  // qudits cannot be moved
46	  qudit(qudit &&) = delete;
47	
48	  // Return the unique id / index for this qudit
49	  std::size_t id() const { return idx; }
50	
