57	/// C++20 variant using templates.
58	
59	/// This function will apply the specified `QuantumOp`. It will check the
60	/// modifier template type and if it is `base`, it will apply the operation to
61	/// any qubits provided as input. If `ctrl`, it will take the first `N-1` qubits
62	/// as the controls and the last qubit as the target.
63	template <typename QuantumOp, typename mod = base, typename... QubitArgs>
64	void oneQubitApply(QubitArgs &...args) {
65	  // Get the name of this operation
66	  auto gateName = QuantumOp::name();
67	  static_assert(std::conjunction<std::is_same<qubit, QubitArgs>...>::value,
68	                "Cannot operate on a qudit with Levels != 2");
69	
70	  // Get the number of input qubits
71	  constexpr std::size_t nArgs = sizeof...(QubitArgs);
72	
73	  // Map the qubits to their unique ids and pack them.
74	  std::vector<QuditInfo> quditInfos{qubitToQuditInfo(args)...};
75	  std::vector<bool> qubitIsNegated{qubitIsNegative(args)...};
76	
77	  // If mod == base, then we just want to apply the gate to all qubits provided.
78	  // This is a broadcast application.
79	  if constexpr (std::is_same_v<mod, base>) {
80	    for (auto &qubit : quditInfos)
81	      getExecutionManager()->apply(gateName, {}, {}, {qubit});
82	
83	    // Nothing left to do, return
84	    return;
85	  }
86	
87	  // If we are here, then `mod` must be control or adjoint. Extract the controls
88	  // and the target
89	  std::vector<QuditInfo> controls(quditInfos.begin(),
90	                                  quditInfos.begin() + nArgs - 1);
91	
92	  // If we have controls, check if any of them are negative controls, and if so
93	  // apply an x.
94	  if (!controls.empty())
95	    for (std::size_t i = 0; i < controls.size(); i++)
96	      if (qubitIsNegated[i])
97	        getExecutionManager()->apply("x", {}, {}, {controls[i]});
98	
99	  // Apply the gate
100	  getExecutionManager()->apply(gateName, {}, controls, {quditInfos.back()},
101	                               std::is_same_v<mod, adj>);
102	
103	  // If we did apply any X ops for a negative control, we need to reverse it.
104	  if (!controls.empty()) {
105	    for (std::size_t i = 0; i < controls.size(); i++) {
106	      if (qubitIsNegated[i]) {
107	        getExecutionManager()->apply("x", {}, {}, {controls[i]});
108	        // fold expression which will reverse the negation
109	        (
110	            [&] {
111	              if (args.is_negative())
112	                args.negate();
113	            }(),
114	            ...);
115	      }
116	    }
117	  }
118	}
