332	  std::transform(ctrls.begin(), ctrls.end(), std::back_inserter(controls),
333	                 [](const auto &q) { return qubitToQuditInfo(q); });
334	  getExecutionManager()->apply(
335	      "swap", {}, controls, {qubitToQuditInfo(src), qubitToQuditInfo(target)});
336	}
