370	/// @brief Apply a general Pauli rotation, takes a qubit register and the size
371	/// must be equal to the Pauli word length.
372	template <typename QubitRange>
373	  requires(std::ranges::range<QubitRange>)
374	void exp_pauli(double theta, QubitRange &&qubits, const char *pauliWord) {
375	  std::vector<QuditInfo> quditInfos;
376	  std::transform(qubits.begin(), qubits.end(), std::back_inserter(quditInfos),
377	                 [](auto &q) { return cudaq::qubitToQuditInfo(q); });
378	  // FIXME: it would be cleaner if we just kept it as a pauli word here
379	  getExecutionManager()->apply("exp_pauli", {theta}, {}, quditInfos, false,
380	                               spin_op::from_word(pauliWord));
381	}
382	
383	/// @brief Apply a general Pauli rotation, takes a qubit register and the size
384	/// must be equal to the Pauli word length.
385	template <typename QubitRange>
386	  requires(std::ranges::range<QubitRange>)
387	void exp_pauli(double theta, QubitRange &&qubits,
388	               const cudaq::pauli_word &pauliWord) {
389	  exp_pauli(theta, qubits, pauliWord.str().c_str());
390	}
391	
392	/// @brief Apply a general Pauli rotation, takes a variadic set of
393	/// qubits, and the number of qubits must be equal to the Pauli word length.
394	template <typename... QubitArgs>
395	void exp_pauli(double theta, const char *pauliWord, QubitArgs &...qubits) {
396	
397	  if (sizeof...(QubitArgs) != std::strlen(pauliWord))
398	    throw std::runtime_error(
399	        "Invalid exp_pauli call, number of qubits != size of pauliWord.");
400	
401	  // Map the qubits to their unique ids and pack them into a std::array
402	  std::vector<QuditInfo> quditInfos{qubitToQuditInfo(qubits)...};
403	  getExecutionManager()->apply("exp_pauli", {theta}, {}, quditInfos, false,
404	                               spin_op::from_word(pauliWord));
405	}
