407	/// @brief Apply a general Pauli rotation with control qubits and a variadic set
408	/// of qubits. The number of qubits must be equal to the Pauli word length.
409	template <typename QuantumRegister, typename... QubitArgs>
410	  requires(std::ranges::range<QuantumRegister>)
411	void exp_pauli(QuantumRegister &ctrls, double theta, const char *pauliWord,
412	               QubitArgs &...qubits) {
413	  std::vector<QuditInfo> controls;
414	  std::transform(ctrls.begin(), ctrls.end(), std::back_inserter(controls),
415	                 [](const auto &q) { return qubitToQuditInfo(q); });
416	  if (sizeof...(QubitArgs) != std::strlen(pauliWord))
417	    throw std::runtime_error(
418	        "Invalid exp_pauli call, number of qubits != size of pauliWord.");
419	
420	  // Map the qubits to their unique ids and pack them into a std::array
421	  std::vector<QuditInfo> quditInfos{qubitToQuditInfo(qubits)...};
422	  getExecutionManager()->apply("exp_pauli", {theta}, controls, quditInfos,
423	                               false, spin_op::from_word(pauliWord));
424	}
