577	// QEC kernel-side operations: `cudaq::detector`, `cudaq::logical_observable`,
578	// and `cudaq::detectors` - they consume `measure_handle`, which is itself
579	// MLIR-mode only. The AST bridge intercepts every call inside `__qpu__`
580	// kernels and lowers it to the corresponding `qec.*` MLIR op. The inline bodies
581	// below are never reached in a built kernel; reaching one means the bridge
582	// missed an interception path, so they throw to fail loudly instead of
583	// producing wrong results.
584	#ifndef CUDAQ_LIBRARY_MODE
585	
586	namespace detail {
587	template <typename T>
588	concept any_measure_result_or_vec =
589	    std::is_same_v<std::remove_cvref_t<T>, measure_result> ||
590	    std::is_same_v<std::remove_cvref_t<T>, std::vector<measure_result>>;
591	} // namespace detail
