624	// Disambiguate from the variadic when an explicit `observable_index` is
625	// passed (the variadic rejects integer arguments via its concept). The
626	// `observable_index` parameter is non-defaulted to keep
627	// `logical_observable(vec)` unambiguously routed through the variadic.
628	inline void logical_observable(const std::vector<measure_result> &ms,
629	                               std::size_t observable_index) {
630	  (void)ms;
631	  (void)observable_index;
632	  throw std::runtime_error(detail::kQpuOnlyHostScopeError);
633	}
