648	// This concept tests if `Kernel` is a `Callable` that takes the arguments,
649	// `Args`, and returns `void`.
650	template <typename Kernel, typename... Args>
651	concept isCallableVoidKernel = requires(Kernel &&k, Args &&...args) {
652	  { k(args...) } -> std::same_as<void>;
653	};
654	
655	template <typename T, typename Signature>
656	concept signature = std::is_convertible_v<T, std::function<Signature>>;
657	
658	template <typename T>
659	concept takes_qubit = signature<T, void(qubit &)>;
660	
661	template <typename T>
662	concept takes_qvector = signature<T, void(qvector<> &)>;
