674	// Control the given cudaq kernel on the given register of control qubits
675	template <typename QuantumKernel, typename QuantumRegister, typename... Args>
676	  requires std::ranges::range<QuantumRegister> &&
677	           isCallableVoidKernel<QuantumKernel, Args...>
678	void control(QuantumKernel &&kernel, QuantumRegister &&ctrl_qubits,
679	             Args &&...args) {
680	  std::vector<std::size_t> ctrls;
681	  for (std::size_t i = 0; i < ctrl_qubits.size(); i++) {
682	    ctrls.push_back(ctrl_qubits[i].id());
683	  }
684	  getExecutionManager()->startCtrlRegion(ctrls);
685	  kernel(std::forward<Args>(args)...);
686	  getExecutionManager()->endCtrlRegion(ctrls.size());
687	}
