689	// Control the given cudaq kernel on the given list of references to control
690	// qubits.
691	template <typename QuantumKernel, typename... Args>
692	  requires isCallableVoidKernel<QuantumKernel, Args...>
693	void control(QuantumKernel &&kernel,
694	             std::vector<std::reference_wrapper<qubit>> &&ctrl_qubits,
695	             Args &&...args) {
696	  std::vector<std::size_t> ctrls;
697	  for (auto &cq : ctrl_qubits) {
698	    ctrls.push_back(cq.get().id());
699	  }
700	  getExecutionManager()->startCtrlRegion(ctrls);
701	  kernel(std::forward<Args>(args)...);
702	  getExecutionManager()->endCtrlRegion(ctrls.size());
703	}
