772	template <size_t N, typename Tuple, size_t... Indices>
773	auto tuple_slice_impl(Tuple &&tuple, std::index_sequence<Indices...>) {
774	  return std::make_tuple(std::get<Indices>(std::forward<Tuple>(tuple))...);
775	}
