783	template <size_t N, typename Tuple, size_t... Indices>
784	auto tuple_slice_last_impl(Tuple &&tuple, std::index_sequence<Indices...>) {
785	  constexpr size_t M = std::tuple_size_v<std::remove_reference_t<Tuple>> - N;
786	  return std::forward_as_tuple(
787	      std::get<M + Indices>(std::forward<Tuple>(tuple))...);
788	}
